// Dedupe by title, trim to the freshest ~40 candidates for the AI editor.
const seen = new Set();
const rows = [];
for (const item of $input.all()) {
  const j = item.json;
  const title = (j.title || '').trim();
  const key = title.toLowerCase();
  if (!title || seen.has(key)) continue;
  seen.add(key);
  rows.push({ title, link: j.link || j.guid || '', source: (j.creator || j.source || 'News'), isoDate: j.isoDate || j.pubDate || '' });
}
rows.sort((a, b) => new Date(b.isoDate) - new Date(a.isoDate));
return [{ json: { candidates: rows.slice(0, 40) } }];

// Parse Claude's JSON array, assemble the NewsFeed, set expiries, pick a lead.
const raw = $json.content?.[0]?.text ?? '[]';
let items;
try { items = JSON.parse(raw.slice(raw.indexOf('['), raw.lastIndexOf(']') + 1)); }
catch (e) { items = []; }

const now = new Date();
const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59).toISOString();
const plus90 = new Date(now.getTime() + 90 * 864e5).toISOString();

items = items.map((it) => ({
  ...it,
  publishedAt: it.publishedAt || now.toISOString(),
  expiresAt: it.expiresAt || (['financiamiento', 'marcas'].includes(it.category) ? endOfMonth : plus90),
}));
items.sort((a, b) => new Date(b.publishedAt) - new Date(a.publishedAt));
items = items.slice(0, 30);
if (items.length && !items.some((i) => i.lead)) items[0].lead = true;

const feed = { updatedAt: now.toISOString(), items };
return [{ json: { feed, body: JSON.stringify(feed) } }];
